const url = $vars.SUPABASE_URL;
const key = $vars.SUPABASE_KEY;
if (!url || !key) throw new Error('Set SUPABASE_URL and SUPABASE_KEY as workflow variables');

const h = { 'apikey': key, 'Authorization': `Bearer ${key}` };

// Fetch latest pipeline run
const runsRes = await this.helpers.httpRequest({
  method: 'GET',
  url: `${url}/rest/v1/pipeline_runs?order=completed_at.desc&limit=1`,
  headers: h
});
const run = Array.isArray(runsRes) && runsRes[0];
if (!run) throw new Error('No pipeline runs found. Run the main pipeline first.');

// Fetch themes for this specific week — scoped by week+year to match pipeline run
const themesRes = await this.helpers.httpRequest({
  method: 'GET',
  url: `${url}/rest/v1/themes?week_number=eq.${run.week_number}&year=eq.${run.year}&order=confidence_score.desc`,
  headers: h
});
const themes = Array.isArray(themesRes) ? themesRes : [];
if (themes.length === 0) throw new Error('No themes found for this week. Run the main pipeline first.');

console.log(`Loaded ${themes.length} themes for Week ${run.week_number}/${run.year} (run: ${run.run_id}, prompt: ${run.prompt_version_id}) — sending to LLM judge`);

// Return one item per theme
return themes.map(t => ({
  json: {
    theme_id: t.theme_id,
    title: t.title,
    summary: t.summary,
    signal_type: t.signal_type,
    confidence_score: t.confidence_score,
    why_it_matters: t.why_it_matters || '',
    what_you_can_do: Array.isArray(t.what_you_can_do) ? t.what_you_can_do.join(' ') : (t.what_you_can_do || ''),
    citations: t.citations || [],
    week_number: run.week_number,
    year: run.year,
    run_id: run.run_id,
    prompt_version_id: run.prompt_version_id
  }
}));

// Build one judge prompt per theme, return as single batch
const themes = $input.all().map(item => item.json);
if (themes.length === 0) throw new Error('No themes received');

const { week_number, year, run_id } = themes[0];

const themeBlocks = themes.map((t, i) => {
  const citationCount = Array.isArray(t.citations) ? t.citations.length : 0;
  const citationDomains = Array.isArray(t.citations)
    ? t.citations.map(c => {
        try { return new URL(c.url).hostname; } catch { return c.url || 'unknown'; }
      }).join(', ')
    : 'none';
  return `--- THEME ${i + 1} ---
theme_id: ${t.theme_id}
title: ${t.title}
signal_type: ${t.signal_type}
confidence_score: ${t.confidence_score}/100
summary: ${t.summary}
why_it_matters: ${t.why_it_matters}
what_you_can_do: ${t.what_you_can_do}
citation_count: ${citationCount}
citation_domains: ${citationDomains}`;
}).join('\n\n');

const prompt = `You are an expert evaluator for an AI Signals Intelligence platform used by enterprise AI Platform Leaders and engineering managers.

Your job is to score each theme from a weekly AI pipeline run on 4 quality dimensions.

TAXONOMY CONTEXT:
This pipeline uses a 2-tier ACT/WATCH system (stored in DB as RISING=ACT, EMERGING=WATCH):
- ACT (RISING in DB): Something specific happened THIS week — a named product release, new API version, published benchmark, or policy announcement — with ≥2 corroborating signals. Warrants action within 5 days.
- WATCH (EMERGING in DB): Ongoing trend, early signal, or single credible source. No specific named this-week trigger. Track over 30 days.

SCORING RUBRIC (1–5 scale):

1. enterprise_relevance
   5 = Critical for AI platform/infra decisions (inference cost, vendor lock-in, architecture choice, compliance)
   4 = Clearly relevant to enterprise AI teams
   3 = Somewhat relevant, niche or tangential
   2 = Mostly irrelevant to enterprise AI platform leaders
   1 = Consumer or academic only — wrong audience

2. signal_type_accuracy (ACT vs WATCH)
   IMPORTANT CONTEXT: The pipeline enforces a balanced mix of max 3 ACT and min 5 WATCH themes per brief. This means some themes with release-like signals may be intentionally classified as WATCH to maintain brief balance. Do NOT penalize WATCH classification on a release-adjacent theme if the theme has ≤2 signals or lacks multiple vendor-domain sources — the pipeline correctly downgrades these to WATCH.
   5 = Tier perfectly matches evidence. ACT: cites a specific named release/event this week with ≥3 multi-source signals from vendor domains. WATCH: correctly identifies an ongoing trend, early signal, or single-source observation.
   4 = Tier is correct and well-supported. WATCH on a specific release is acceptable if the theme has only 1-2 signals or all signals are from GitHub/non-vendor domains.
   3 = Tier is plausible but evidence is borderline (e.g., ACT but only general industry news, no specific release named)
   2 = Tier is clearly wrong — e.g., ACT assigned to a broad evergreen category with no this-week event and no named product; or WATCH assigned to a confirmed major vendor release with ≥3 official vendor-domain sources
   1 = Completely wrong classification

3. actionability
   5 = what_you_can_do gives specific, concrete next steps achievable within 5 business days (evaluate X vendor, run Y benchmark, update Z config)
   4 = Good concrete guidance with some specificity
   3 = Reasonable guidance but vague or generic
   2 = Vague advice ("monitor this", "stay informed", "keep an eye on", "consider exploring", "engage with experts")
   1 = No useful action or missing entirely

4. summary_quality
   5 = 4–5 sentences, names specific product/version/vendor, includes one number or benchmark, covers technical mechanism and ecosystem impact
   4 = Good summary, minor improvements possible
   3 = Adequate but stays at headline level — no specific version, no number, no mechanism
   2 = Vague, inaccurate, or too long (>5 sentences)
   1 = Confusing, wrong, or meaningless

OUTPUT FORMAT — respond with valid JSON only, no prose before or after:
{
  "themes": [
    {
      "theme_id": "<theme_id>",
      "title": "<title>",
      "scores": {
        "enterprise_relevance": <1-5>,
        "signal_type_accuracy": <1-5>,
        "actionability": <1-5>,
        "summary_quality": <1-5>,
        "overall": <average to 1 decimal>
      },
      "flags": ["<specific issue to fix>"],
      "highlights": ["<notable strength>"]
    }
  ]
}

Rules:
- flags = specific problems to fix (empty array if none)
- highlights = notable strengths (empty array if none)
- Be strict: 4+ means genuinely good, not just acceptable
- Do not pad scores. "monitor this space" = actionability 2. Broad category with no named release = signal_type_accuracy 2 if marked ACT.
- For signal_type_accuracy: ACT requires a SPECIFIC named product/version/event this week. If you cannot identify what specifically was released or announced, it should be WATCH.

THEMES TO EVALUATE:

${themeBlocks}`;

console.log(`Built judge prompt for ${themes.length} themes (${prompt.length} chars)`);
return [{ json: { prompt, themes_input: themes, week_number, year, run_id } }];

const { prompt, themes_input, week_number, year, run_id } = $input.first().json;

// Read OpenAI key from workflow variable
const openaiKey = $vars.OPENAI_API_KEY;
if (!openaiKey) throw new Error('Set OPENAI_API_KEY as a workflow variable (Settings → Variables)');

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.openai.com/v1/chat/completions',
  headers: {
    'Content-Type': 'application/json',
    'Authorization': `Bearer ${openaiKey}`
  },
  body: JSON.stringify({
    model: 'gpt-4-turbo',
    temperature: 0.2,
    max_tokens: 4000,
    response_format: { type: 'json_object' },
    messages: [
      {
        role: 'system',
        content: 'You are a strict quality evaluator for an AI Signals Intelligence platform. Always respond with valid JSON only.'
      },
      {
        role: 'user',
        content: prompt
      }
    ]
  })
});

console.log(`GPT-4 Turbo responded — tokens used: ${response.usage?.total_tokens || 'N/A'}`);

// Pass through all context plus the raw response for the parse node
return [{ json: { ...response, week_number, year, run_id, themes_input } }];

const item = $input.first().json;
const { week_number, year, run_id, themes_input } = item;

// Parse GPT response
let parsed;
try {
  const raw = item.choices[0].message.content;
  parsed = typeof raw === 'string' ? JSON.parse(raw) : raw;
} catch (e) {
  throw new Error(`Failed to parse GPT-4 response: ${e.message}`);
}

const judgedThemes = parsed.themes || [];
if (judgedThemes.length === 0) throw new Error('LLM returned no theme scores');

// Build aggregate stats
const dims = ['enterprise_relevance', 'signal_type_accuracy', 'actionability', 'summary_quality'];
const avg = arr => arr.length ? Math.round((arr.reduce((a, b) => a + b, 0) / arr.length) * 10) / 10 : 0;

const allOverall = judgedThemes.map(t => parseFloat(t.scores?.overall || 0));
const dimAverages = {};
dims.forEach(d => {
  dimAverages[d] = avg(judgedThemes.map(t => t.scores?.[d] || 0));
});

const sorted = [...judgedThemes].sort((a, b) => (b.scores?.overall || 0) - (a.scores?.overall || 0));
const topTheme = sorted[0];
const weakestTheme = sorted[sorted.length - 1];

// Collect all flags across themes
const allFlags = judgedThemes.flatMap(t =>
  (t.flags || []).map(f => `[${t.title}] ${f}`)
);

const overallAvg = avg(allOverall);
const verdict = overallAvg >= 4.2 ? '🟢 PUBLICATION READY'
  : overallAvg >= 3.5 ? '🟡 REVIEW FLAGGED THEMES'
  : '🔴 NEEDS SIGNIFICANT REVISION';

const tokens = item.usage || {};

// Build markdown report
const bar = score => '█'.repeat(Math.round(score)) + '░'.repeat(5 - Math.round(score));

const themeRows = judgedThemes.map(t => {
  const s = t.scores;
  return `| ${t.title.substring(0, 40)} | ${s.enterprise_relevance} | ${s.signal_type_accuracy} | ${s.actionability} | ${s.summary_quality} | **${s.overall}** |${t.flags?.length ? ` ⚠️ ${t.flags.length} flag(s)` : ' ✅'} |`;
}).join('\n');

const flagSection = allFlags.length > 0
  ? `## ⚠️ Flags to Address\n${allFlags.map(f => `- ${f}`).join('\n')}`
  : `## ✅ No Flags\nAll themes passed quality review.`;

const report = [
  `# CalmFalcon LLM Eval — Week ${week_number}/${year}`,
  `## ${verdict}  ·  Overall Score: ${overallAvg}/5.0`,
  ``,
  `**Run:** \`${run_id}\`  ·  **Themes judged:** ${judgedThemes.length}  ·  **LLM tokens used:** ${tokens.total_tokens || 'N/A'}`,
  ``,
  `## Dimension Averages`,
  `| Dimension | Avg Score | Visual |`,
  `|-----------|-----------|--------|`,
  ...dims.map(d => `| ${d.replace(/_/g, ' ')} | ${dimAverages[d]}/5.0 | ${bar(dimAverages[d])} |`),
  ``,
  `## Per-Theme Scores`,
  `| Theme | Relevance | Signal Type | Actionability | Summary | Overall | Status |`,
  `|-------|-----------|-------------|---------------|---------|---------|--------|`,
  themeRows,
  ``,
  `## 🏆 Top Theme: ${topTheme?.title}`,
  `Score: ${topTheme?.scores?.overall}/5.0`,
  ...(topTheme?.highlights || []).map(h => `- ${h}`),
  ``,
  `## 📉 Weakest Theme: ${weakestTheme?.title}`,
  `Score: ${weakestTheme?.scores?.overall}/5.0`,
  ...(weakestTheme?.flags || []).map(f => `- ${f}`),
  ``,
  flagSection
].join('\n');

console.log(report);
console.log(`LLM Judge complete — overall avg: ${overallAvg}/5.0 | ${allFlags.length} flags | ${tokens.total_tokens || '?'} tokens`);

return [{ json: {
  report,
  verdict,
  overall_score: overallAvg,
  dim_averages: dimAverages,
  themes_scored: judgedThemes,
  top_theme: { title: topTheme?.title, score: topTheme?.scores?.overall },
  weakest_theme: { title: weakestTheme?.title, score: weakestTheme?.scores?.overall },
  total_flags: allFlags.length,
  all_flags: allFlags,
  tokens_used: tokens.total_tokens || null,
  week_number,
  year,
  run_id
} }];

const { report, verdict, overall_score, dim_averages, themes_scored, total_flags, week_number, year, run_id } = $input.first().json;

const url = $vars.SUPABASE_URL;
const key = $vars.SUPABASE_KEY;
if (!url || !key) throw new Error('Set SUPABASE_URL and SUPABASE_KEY as workflow variables');

const row = {
  eval_type: 'llm_judge',
  week_number,
  year,
  run_id: run_id || null,
  score: `${overall_score}/5.0`,
  overall_verdict: verdict,
  report_markdown: report,
  themes_scored: themes_scored || [],
  dim_averages: dim_averages || {}
};

const res = await this.helpers.httpRequest({
  method: 'POST',
  url: `${url}/rest/v1/eval_reports`,
  headers: {
    'apikey': key,
    'Authorization': `Bearer ${key}`,
    'Content-Type': 'application/json',
    'Prefer': 'return=representation'
  },
  body: JSON.stringify([row])
});

console.log(`LLM Judge report saved — Week ${week_number}/${year} | score ${overall_score}/5.0 | ${total_flags} flags`);
return [{ json: { saved: true, verdict, overall_score, total_flags, week_number, year } }];
